import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface PaymentBreakdown {
  month: string;
  principal: number;
  interest: number;
}

interface LoanDetails {
  remainingBalance: number;
  nextPayment: {
    amount: number;
    dueDate: string;
  };
}

interface WidgetData {
  loanDetails: LoanDetails;
  paymentBreakdown: PaymentBreakdown[];
}

export default function Widget() {
  const { loanDetails, paymentBreakdown } = response.data as WidgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Remaining Balance
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#4A90E2' }}>
              ${loanDetails.remainingBalance.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
              Next Payment: ${loanDetails.nextPayment.amount.toFixed(2)} due on {loanDetails.nextPayment.dueDate}
            </Typography>
          </Box>

          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#D0021B' }}>
              Payment Breakdown
            </Typography>
            <BarChart
              height={140}
              series={[
                {
                  data: paymentBreakdown.map(p => p.principal),
                  color: '#4A90E2',
                  label: 'Principal',
                },
                {
                  data: paymentBreakdown.map(p => p.interest),
                  color: '#D0021B',
                  label: 'Interest',
                },
              ]}
              xAxis={[
                {
                  data: paymentBreakdown.map(p => p.month),
                  scaleType: 'band',
                  tickLabelStyle: {
                    fontSize: 11,
                    fill: '#6B7280',
                  },
                }
              ]}
              margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
              sx={{
                '& .MuiBarElement-root': {
                  rx: 4,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
